    fun find(themeName: String, isDark: Boolean): SharePalette? =
        palettes[themeName + ":" + if (isDark) "Dark" else "Light"]

    /** 兜底主题：找不到时返回 WarmBrownRed Dark。 */
    val fallback: SharePalette = palettes.getValue("WarmBrownRed:Dark")
